INSERT INTO articles (title, slug, summary, content, threat_level, category, cves, affected_products, threat_actors, industries, attack_vector, source, source_url, published_at, updated_at, discovered_at, exploited_at, patched_at, verified, verified_by, tags, region) VALUES
('Critical Zero-Day in Palo Alto PAN-OS Firewalls Under Active Mass Exploitation', 'palo-alto-pan-os-zero-day-mass-exploitation', 'A critical unauthenticated RCE in PAN-OS GlobalProtect is being mass exploited. Over 25,000 devices vulnerable. CISA issues emergency directive.', 'Palo Alto Networks has confirmed active exploitation of CVE-2026-0015, a critical command injection vulnerability in the GlobalProtect gateway. Unauthenticated attackers can execute arbitrary commands as root via crafted HTTPS requests. Volexity first observed exploitation on March 26 with rapid escalation. CISA issued Emergency Directive 26-02 requiring federal agencies to patch within 48 hours.', 'critical', 'zero-day', '{"CVE-2026-0015"}', '{"PAN-OS 11.1","PAN-OS 11.0","PAN-OS 10.2","GlobalProtect Gateway"}', '{}', '{"government","finance","healthcare","technology","defense"}', 'Network / HTTPS GlobalProtect Gateway', 'Palo Alto Networks PSIRT', 'https://security.paloaltonetworks.com', '2026-03-31T18:00:00Z', '2026-04-01T08:00:00Z', '2026-03-26T00:00:00Z', '2026-03-26T00:00:00Z', '2026-03-30T00:00:00Z', true, '{"CISA","Palo Alto Networks","Volexity"}', '{"zero-day","firewall","mass-exploitation","emergency-directive"}', 'Global'),

('Salt Typhoon Compromises Three Additional US Telecom Providers', 'salt-typhoon-three-more-us-telecoms', 'CISA and FBI confirm Salt Typhoon has compromised three additional US telecom providers, totaling twelve. Lawful intercept systems accessed.', 'Chinese state-sponsored group Salt Typhoon has expanded its campaign to twelve US telecom companies. Investigators confirmed access to lawful intercept systems, call detail records, and metadata for senior government officials. Remediation complicated by firmware-level implants on core routing infrastructure.', 'critical', 'apt', '{}', '{"Cisco IOS XR","Juniper Junos","Telecom Core Routers","Lawful Intercept Systems"}', '{"Salt Typhoon"}', '{"telecommunications","government","defense"}', 'Network Infrastructure / Router Exploitation', 'CISA / FBI Joint Advisory', 'https://www.cisa.gov/news-events/cybersecurity-advisories', '2026-03-30T14:00:00Z', '2026-03-31T10:00:00Z', '2024-09-01T00:00:00Z', '2024-09-01T00:00:00Z', NULL, true, '{"CISA","FBI","NSA"}', '{"telecom","state-sponsored","espionage","lawful-intercept"}', 'United States'),

('LockBit 5.0 Deploys AI-Powered Ransomware with Automated Network Mapping', 'lockbit-5-ai-powered-ransomware', 'LockBit 5.0 features AI module for automated reconnaissance, high-value target identification, and optimized encryption timing.', 'LockBit 5.0 includes "LockBrain" — an AI module that automates network recon, identifies critical systems and backups, and determines optimal encryption timing based on victim activity patterns. Generates customized ransom notes from victim financial data. Average demands exceed $5M.', 'critical', 'ransomware', '{}', '{"Windows Server 2022/2025","VMware ESXi 8.x","Linux Enterprise","Active Directory"}', '{"LockBit"}', '{"healthcare","finance","manufacturing"}', 'RDP / VPN Exploitation / AI-Assisted Lateral Movement', 'FBI Flash Alert', 'https://www.ic3.gov', '2026-03-29T16:00:00Z', '2026-03-30T12:00:00Z', '2026-03-22T00:00:00Z', '2026-03-22T00:00:00Z', NULL, true, '{"FBI","CISA"}', '{"ransomware","ai-assisted","lockbit"}', 'Global'),

('Critical RCE Chain in Microsoft Azure Kubernetes Service Exposes Cloud Workloads', 'azure-aks-rce-chain-cloud-workloads', 'Three chained vulnerabilities in Azure AKS allow container escape and host node RCE. 40% of AKS clusters were vulnerable before patching.', 'Wiz Research discovered a chain: CVE-2026-21345 (OverlayFS container escape), CVE-2026-21346 (kubelet auth bypass), CVE-2026-21347 (RBAC privilege escalation to cluster-admin). Microsoft has auto-patched managed clusters.', 'critical', 'vulnerability', '{"CVE-2026-21345","CVE-2026-21346","CVE-2026-21347"}', '{"Azure Kubernetes Service","Azure Container Instances","Linux Kernel 6.x"}', '{}', '{"technology","finance","healthcare","government"}', 'Container Escape / Privilege Escalation', 'Microsoft MSRC / Wiz Research', 'https://msrc.microsoft.com', '2026-03-28T20:00:00Z', '2026-03-29T14:00:00Z', '2026-03-15T00:00:00Z', NULL, '2026-03-28T00:00:00Z', true, '{"Microsoft","Wiz Research","CISA"}', '{"cloud","kubernetes","container-escape","azure"}', 'Global'),

('Scattered Spider Breaches Major US Health Insurer — 8.2M Records Exposed', 'scattered-spider-health-insurer-breach', 'Scattered Spider breaches top-5 US health insurer via help desk social engineering. 8.2M member records including PHI exfiltrated.', 'Scattered Spider social-engineered the IT help desk into resetting an exec MFA token. Deployed legitimate RMM tools, exfiltrated 8.2M records including SSNs, medical diagnoses, prescriptions. Posted sample on leak site with $15M ransom demand. HHS opened HIPAA investigation.', 'critical', 'data-breach', '{}', '{"Okta","Microsoft 365","Azure AD","ServiceNow"}', '{"Scattered Spider"}', '{"healthcare","finance"}', 'Social Engineering / Help Desk Manipulation', 'HHS / FBI Joint Advisory', 'https://www.hhs.gov', '2026-03-27T12:00:00Z', '2026-03-28T16:00:00Z', '2026-03-20T00:00:00Z', '2026-03-15T00:00:00Z', NULL, true, '{"HHS","FBI","CISA"}', '{"data-breach","healthcare","social-engineering","hipaa"}', 'United States'),

('APT29 OAuth Consent Phishing Campaign Targets 14 NATO Governments', 'apt29-oauth-consent-phishing-nato', 'APT29 compromises 500+ government accounts across NATO via malicious Azure app registrations requesting mail and file access.', 'APT29 registers malicious Azure apps requesting mail.read and files.read permissions. Targets receive phishing from compromised legitimate government accounts. Once consent granted, persistent access without needing the password. Microsoft has revoked malicious apps and published IOCs.', 'high', 'apt', '{}', '{"Microsoft 365","Azure AD","Microsoft Entra ID","Outlook"}', '{"APT29"}', '{"government","defense"}', 'OAuth Consent Phishing', 'Microsoft Threat Intelligence', 'https://www.microsoft.com/security/blog', '2026-03-26T10:00:00Z', '2026-03-27T08:00:00Z', '2026-03-18T00:00:00Z', '2026-03-18T00:00:00Z', NULL, true, '{"Microsoft","CISA","NATO CCDCOE"}', '{"apt","oauth","phishing","state-sponsored","nato"}', 'Europe / NATO'),

('Supply Chain Attack Compromises Python AI/ML Libraries — 45M Downloads', 'pypi-supply-chain-ai-ml-libraries', 'Three popular Python AI/ML packages on PyPI compromised. Credential-stealing code targets AWS, GCP, Azure, and AI API keys.', 'JFrog uncovered compromised maintainer accounts on three AI/ML packages with 45M combined weekly downloads. Malicious versions exfiltrate cloud credentials and AI service API keys (OpenAI, Anthropic, Hugging Face). Live for 72 hours before detection.', 'high', 'supply-chain', '{"CVE-2026-31001","CVE-2026-31002","CVE-2026-31003"}', '{"PyPI ecosystem","Python applications","AWS","GCP","Azure"}', '{}', '{"technology","finance","healthcare"}', 'Supply Chain / Package Repository', 'JFrog Security Research', 'https://jfrog.com/blog', '2026-03-25T22:00:00Z', '2026-03-26T14:00:00Z', '2026-03-25T16:00:00Z', NULL, NULL, true, '{"JFrog","PyPI Security","CISA"}', '{"supply-chain","pypi","ai-ml","credential-theft"}', 'Global'),

('Volt Typhoon in US Water Systems Triggers EPA Emergency Order', 'volt-typhoon-water-systems-emergency', 'EPA emergency order after confirming Volt Typhoon access to water treatment SCADA systems serving 20M+ Americans. Chemical dosing manipulation capability confirmed.', 'CISA confirmed Volt Typhoon maintains persistent access to water treatment SCADA systems across six states serving 20M+ Americans. Group demonstrated capability to manipulate chemical dosing systems. Present in some systems since 2023. Emergency response teams deployed.', 'critical', 'apt', '{}', '{"SCADA Systems","PLCs","Historian Servers","HMI Systems","OT Networks"}', '{"Volt Typhoon"}', '{"energy","government","healthcare"}', 'OT Device Exploitation / IT-OT Lateral Movement', 'EPA / CISA Emergency Advisory', 'https://www.epa.gov', '2026-03-24T15:00:00Z', '2026-03-25T11:00:00Z', '2023-06-01T00:00:00Z', '2023-06-01T00:00:00Z', NULL, true, '{"EPA","CISA","FBI","NSA"}', '{"critical-infrastructure","water","scada","ot-security"}', 'United States'),

('Chrome Zero-Day Exploited by Spyware Vendor Against Journalists', 'chrome-zero-day-spyware-journalists', 'Google patches V8 zero-day exploited by commercial spyware vendor. One-click full chain achieves RCE targeting journalists and activists.', 'CVE-2026-1893 is a V8 type confusion enabling full sandbox escape via single malicious link. Google TAG identified a European spyware vendor targeting journalists, activists, and opposition politicians. Payload includes device monitoring, encrypted message interception, mic/camera activation.', 'high', 'zero-day', '{"CVE-2026-1893"}', '{"Google Chrome 134","Microsoft Edge","Chromium Browsers","Android WebView"}', '{}', '{"technology","government"}', 'Web / One-Click Exploit', 'Google Threat Analysis Group', 'https://blog.google/threat-analysis-group', '2026-03-23T20:00:00Z', '2026-03-24T10:00:00Z', '2026-03-19T00:00:00Z', '2026-03-19T00:00:00Z', '2026-03-23T00:00:00Z', true, '{"Google TAG"}', '{"zero-day","spyware","browser","journalists","surveillance"}', 'Global'),

('Cl0p Mass Exploits Cleo File Transfer Zero-Day — 600+ Organizations Hit', 'cl0p-cleo-file-transfer-zero-day', 'Cl0p launches fourth major file transfer campaign exploiting Cleo Harmony, VLTrader, and LexiCom zero-day. Systematic data exfiltration ongoing.', 'CVE-2026-27891 is a deserialization flaw in Cleo products allowing unauthenticated RCE. Huntress detected exploitation March 18. Over 600 organizations compromised. This is Cl0p fourth file transfer campaign after Accellion, GoAnywhere, and MOVEit.', 'high', 'supply-chain', '{"CVE-2026-27891"}', '{"Cleo Harmony","Cleo VLTrader","Cleo LexiCom"}', '{"Cl0p"}', '{"finance","retail","manufacturing","healthcare","government"}', 'File Transfer Appliance Exploitation', 'Huntress / Cleo Advisory', 'https://www.cleo.com', '2026-03-22T11:00:00Z', '2026-03-23T09:00:00Z', '2026-03-18T00:00:00Z', '2026-03-18T00:00:00Z', '2026-03-21T00:00:00Z', true, '{"Huntress","CISA","Cleo"}', '{"file-transfer","zero-day","mass-exploitation","cl0p"}', 'Global'),

('Critical Fortinet FortiManager Flaw Enables Managed Firewall Takeover', 'fortinet-fortimanager-remote-takeover', 'CVE-2026-48788 allows registration of rogue FortiGate devices to FortiManager, enabling config push to entire managed firewall estate.', 'Unauthenticated attackers can register rogue FortiGate devices and push malicious configs to all managed firewalls. CVSS 9.8. Mandiant links exploitation to UNC3886 deploying firmware implants surviving factory resets. Patch immediately and audit device registrations.', 'critical', 'vulnerability', '{"CVE-2026-48788"}', '{"FortiManager 7.4","FortiManager 7.6","FortiGate Firewalls"}', '{"Salt Typhoon"}', '{"government","finance","energy","telecommunications","defense"}', 'Network / FortiManager Protocol', 'Fortinet PSIRT / Mandiant', 'https://www.fortiguard.com', '2026-03-21T16:00:00Z', '2026-03-22T12:00:00Z', '2026-03-10T00:00:00Z', '2026-03-12T00:00:00Z', '2026-03-21T00:00:00Z', true, '{"CISA","Fortinet PSIRT","Mandiant"}', '{"firewall","fortimanager","network-edge","firmware-implant"}', 'Global'),

('NIST NVD Backlog Exceeds 30,000 Unanalyzed CVEs', 'nist-nvd-backlog-crisis-30k-cves', 'NVD backlog doubles year-over-year, creating blind spots in vuln management. Industry coalition demands congressional emergency funding.', 'Over 30,000 CVEs lack CVSS scores and CPE data. Security teams increasingly relying on VulnCheck, OSV, and vendor advisories. Particularly impactful for healthcare and government compliance requirements. CISA Vulnrichment program helping but incomplete.', 'medium', 'vulnerability', '{}', '{"NIST NVD","Vulnerability Management Tools","CVSS","CPE Dictionary"}', '{}', '{"technology","healthcare","government","finance"}', 'N/A — Systemic Risk', 'Cybersecurity Coalition', 'https://www.nist.gov/nvd', '2026-03-20T09:00:00Z', '2026-03-21T15:00:00Z', '2025-02-01T00:00:00Z', NULL, NULL, true, '{"NIST","CISA"}', '{"nvd","vulnerability-management","systemic-risk","compliance"}', 'United States');
